import React from "react";

class Suggestions extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      suggestions: [],
      loading: true,
      error: null,
    };
  }

  componentDidMount() {
    fetch("http://localhost:3000/api/fpgrowth")
      .then((res) => res.json())
      .then((data) => {
        const sample = Array.isArray(data)
          ? data
          : [
              { items: ["Laptop", "Mouse"], support: 0.15 },
              { items: ["iPhone", "AirPods"], support: 0.12 },
              { items: ["Phone Case", "Charger"], support: 0.08 },
            ];

        this.setState({ suggestions: sample, loading: false });
      })
      .catch((err) => {
        this.setState({ error: "Không thể tải dữ liệu", loading: false });
      });
  }

  render() {
    const { suggestions, loading, error } = this.state;

    if (loading) {
      return React.createElement("div", null, "Đang tải gợi ý...");
    }

    if (error) {
      return React.createElement("div", null, error);
    }

    const suggestionElements = suggestions.map((item, index) =>
      React.createElement(
        "div",
        { key: index, className: "suggestion" },
        React.createElement(
          "p",
          null,
          `🛒 Sản phẩm: ${item.items.join(" + ")}`
        ),
        React.createElement(
          "p",
          null,
          `📈 Tỷ lệ mua cùng: ${(item.support * 100).toFixed(1)}%`
        )
      )
    );

    return React.createElement(
      "div",
      { className: "container" },
      React.createElement(
        "h2",
        null,
        "Gợi ý sản phẩm thường được mua cùng nhau"
      ),
      ...suggestionElements
    );
  }
}

export default Suggestions;
